const user = $('Get User').item.json;
const logs = $('Get Logs').all().map(i => i.json);
const n = logs.length || 1;
const avgProt = (logs.reduce((s,d)=>s+(parseFloat(d.protein_g)||0),0)/n).toFixed(1);
const avgCal = Math.round(logs.reduce((s,d)=>s+(d.calories_consumed||0),0)/n);
const avgSleep = (logs.reduce((s,d)=>s+(parseFloat(d.sleep_hours)||0),0)/n).toFixed(1);
const avgEnergy = (logs.reduce((s,d)=>s+(d.energy_level||0),0)/n).toFixed(1);
const foodSample = logs.filter(d=>d.food_description).slice(0,3).map((d,i)=>`Day ${i+1}: ${d.food_description}`).join('\n') || 'No food logs yet';
const prompt = `You are FitBuddy AI, an expert nutrition coach. Provide personalized supplement advice.

USER: ${user.first_name}, Age ${user.age}, ${user.gender}, ${user.weight_kg}kg
Goal: ${user.goal} | Activity: ${user.activity_level} | Daily target: ${user.daily_calorie_target} kcal

7-DAY AVERAGES:
Calories: ${avgCal} kcal | Protein: ${avgProt}g | Sleep: ${avgSleep}h | Energy: ${avgEnergy}/10

RECENT FOOD:
${foodSample}

💊 SUPPLEMENT ADVICE
Based on the goal (${user.goal}), recent food logs, and energy patterns:
- Identify 1-2 nutritional gaps
- Recommend 2-3 specific supplements with dosage and timing
- Flag any to avoid
- Always note: consult a healthcare provider before starting supplements`;
return [{ json: { prompt, userId: user.id, telegramId: user.telegram_id, goal: user.goal } }];

